#include <cmath>
#include <cstdio>

#define PI   3.14159265358979323846
#define PI_2 1.57079632679489661923
#define PI_4 0.78539816339744830962

#define eps 1e-6
#define DINF 1e200
using namespace std;
struct point
{
    double x,y;
    double ang;
    point(){}
    point(double _x,double _y){x=_x;y=_y;}
    void read()
    {
        scanf("%lf%lf",&x,&y);
    }
    void write()
    {
        printf("%lf %lf\n",x,y);
    }
};

bool dy(double x,double y)  {return x > y + eps;}          // x > y
bool xy(double x,double y)  {return x < y - eps;}          // x < y
bool dyd(double x,double y) {return x > y - eps;}          // x >= y
bool xyd(double x,double y) {return x < y + eps;}          // x <= y
bool dd(double x,double y)  {return fabs( x - y ) < eps;}  // x == y

double cross(point a,point b,point c)//向量 ac 在 ab 的方向
{
    return (c.x - a.x)*(b.y - a.y) - (b.x - a.x)*(c.y - a.y);
}

double dis(point a,point b)
{
    return(sqrt((a.x-b.x)*(a.x-b.x)+(a.y-b.y)*(a.y-b.y)));
}

int n,m,k;
point pt[100005];
point p[100005];
int cnt;
int pk;

int cmp(point a, point b)
{
    return(xy(a.ang,b.ang) || (dd(a.ang,b.ang) && dis(a,pt[0])<dis(b,pt[0])));
}
int panduan(point x)
{
    int l=1,r=n-1;
    int mid;
    int pos;
    if(xy(x.ang,pt[l].ang) || dy(x.ang,pt[r].ang)) return 0;
    while(l<r)
    {
        mid=(l+r)/2;
        if(pt[mid].ang<=x.ang)
        {
            l=mid+1;
            pos=l;
        }
        else
        {
            r=mid;
            pos=r;
        }

    }
    if(pos==n) pos--;
    if(dyd(cross(pt[pos],pt[pos-1],x),0)) return 1;
    return 0;
}

int main()
{
    scanf("%d%d%d",&n,&m,&k);
    cnt=0;
    pk=0;
    for(int i=0;i<n;i++)
    {
        pt[i].read();
        if(pt[pk].y>pt[i].y) pk=i;
        else if(pt[pk].y==pt[i].y && pt[pk].x>pt[i].x) pk=i;
    }
    swap(pt[pk],pt[0]);
    for(int i=0;i<n;i++)
    {
        pt[i].ang=atan2(pt[i].y-pt[0].y,pt[i].x-pt[0].x);
    }
    sort(pt+1,pt+n,cmp);

//    for(int i=0;i<n;i++) pt[i].write();
    pt[n]=pt[0];
    for(int i=0;i<m;i++)
    {
        p[i].read();
        p[i].ang=atan2(p[i].y-pt[0].y,p[i].x-pt[0].x);
    }
    for(int i=0;i<m;i++)
        if(panduan(p[i]))
        {
            cnt++;
            //cout<<i<<" ok"<<endl;
        }
    if(cnt>=k) puts("YES");
    else puts("NO");
    return 0;
}
