long long phi(long long n)
{
    long long i,m=n;
    for(i=2;i*i<=n;i++)
    {
        if(n%i==0)
        {
            m=m-m/i;
            while(n%i==0)  n/=i;
        }
    }
    if(n>1)
        m=m-m/n;
    return m;
}
