    c = Mat();
    c.n = a.n,c.m = b.m;
    for(int i=1;i<=a.n;i++) {
        for(int k=1;k<=a.m;k++) {
            if(a.mat[i][k]!=0){  //这里优化一下，对于稀疏矩阵可以节省一半左右的时间
